/**
 * Copy the appropriate .forgeignore template to the project root.
 *
 * Provenance (1.6.1): every generated .forgeignore is prefixed with a
 *   # Generated by ui-forge@<version> from <sourceRel>
 * header. On re-install, files that still carry the header are safe to
 * replace (e.g. switching themes from shadcn → stackshift). Files without
 * the header are treated as user-customized and preserved untouched.
 * Power users can pass --force-forgeignore to clobber a user-owned file.
 */
import { existsSync, readFileSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';
import { ensureDir, fromPosix } from '../fs-utils.js';
export const FORGEIGNORE_PROVENANCE_PREFIX = '# Generated by ui-forge@';
/**
 * Sentinel marker embedded in the StackShift baseline template (which is
 * written without a provenance header so users can edit freely). Lets the
 * installer recognize an untouched template on re-install and replace it
 * when the user switches away from stackshift/paired mode. Users who delete
 * this line are signalling "I own this file" — the installer then leaves
 * it alone, the same as any other user-owned forgeignore.
 */
export const FORGEIGNORE_STACKSHIFT_SENTINEL = '# ui-forge:stackshift-baseline';
/**
 * Pre-1.6.6 stackshift templates were written without a provenance header
 * AND without the sentinel — the only signature is the literal first line
 * of the bundled template. Detect them so a retroactive switch-away cleanup
 * works on installs upgraded from 1.6.5 or earlier.
 */
const LEGACY_STACKSHIFT_FIRST_LINE = '#StackShift Workflow Skill';
function isUiForgeOwned(body) {
    // Tolerate leading whitespace / BOM but require the marker to be in the
    // first ~512 bytes — both markers we write live in the first few lines.
    const head = body.slice(0, 512);
    if (head.includes(FORGEIGNORE_PROVENANCE_PREFIX))
        return true;
    if (head.includes(FORGEIGNORE_STACKSHIFT_SENTINEL))
        return true;
    // Legacy pre-1.6.6 stackshift template: starts with a known signature line.
    if (head.trimStart().startsWith(LEGACY_STACKSHIFT_FIRST_LINE))
        return true;
    return false;
}
function provenanceHeader(version, sourceRel) {
    return (`${FORGEIGNORE_PROVENANCE_PREFIX}${version} from ${sourceRel}\n` +
        `# Delete this header to mark the file as user-owned (ui-forge will not overwrite it).\n` +
        `# Re-run \`ui-forge repair\` to regenerate after changing themes.\n`);
}
export function writeForgeignore(args) {
    const { cwd, sourceRoot, sourceRel, version, force, skipProvenance, dryRun } = args;
    const src = join(sourceRoot, fromPosix(sourceRel));
    const dest = join(cwd, '.forgeignore');
    if (!existsSync(src)) {
        return { destPath: dest, written: false, reason: 'no-source' };
    }
    if (dryRun) {
        return { destPath: dest, written: false, reason: 'dry-run' };
    }
    const sourceBody = readFileSync(src, 'utf8');
    // skipProvenance: write the source body verbatim. The file is immediately
    // user-owned (no header) so the isUiForgeOwned() check below treats any
    // future re-install as "preserve untouched" unless --force-forgeignore.
    if (skipProvenance) {
        if (existsSync(dest)) {
            const existing = readFileSync(dest, 'utf8');
            // If a prior install left a header, allow replacement so users switching
            // INTO a curated template can pick it up cleanly. Otherwise treat as
            // user-owned.
            if (existing === sourceBody) {
                return { destPath: dest, written: false, reason: 'no-provenance' };
            }
            if (isUiForgeOwned(existing) || force) {
                ensureDir(cwd);
                writeFileSync(dest, sourceBody);
                return { destPath: dest, written: true, reason: 'no-provenance' };
            }
            return { destPath: dest, written: false, reason: 'preserved-user-owned' };
        }
        ensureDir(cwd);
        writeFileSync(dest, sourceBody);
        return { destPath: dest, written: true, reason: 'no-provenance' };
    }
    const header = provenanceHeader(version, sourceRel);
    const finalBody = `${header}\n${sourceBody}`;
    if (existsSync(dest)) {
        const existing = readFileSync(dest, 'utf8');
        if (existing === finalBody) {
            // Already up-to-date; no-op (idempotent).
            return { destPath: dest, written: false, reason: 'replaced' };
        }
        if (isUiForgeOwned(existing) || force) {
            ensureDir(cwd);
            writeFileSync(dest, finalBody);
            return { destPath: dest, written: true, reason: force ? 'forced' : 'replaced' };
        }
        // User-owned — leave alone.
        return { destPath: dest, written: false, reason: 'preserved-user-owned' };
    }
    ensureDir(cwd);
    writeFileSync(dest, finalBody);
    return { destPath: dest, written: true, reason: 'created' };
}
